        if (resourceDao.getById("res-1") != null) return
        resourceDao.upsert(
            ResourceEntity(
                id = "res-1",
                name = "Premium Hall",
                category = "Operations",
                availableUnits = 4,
                unitPrice = 25.50,
                allergens = "none",
            ),
        )
    }

