import com.eaglepoint.task136.shared.viewmodel.ResourceListViewModel

@Composable
fun ResourceListScreen(
    viewModel: ResourceListViewModel,
    orderWorkflowViewModel: OrderWorkflowViewModel,
    meetingWorkflowViewModel: MeetingWorkflowViewModel,
    orderFinanceViewModel: OrderFinanceViewModel,
    roleLabel: String,
    actorId: String,
    onActivity: () -> Unit,
    onLogout: () -> Unit,
) {
    val state by viewModel.state.collectAsState()
    val orderState by orderWorkflowViewModel.state.collectAsState()
    val meetingState by meetingWorkflowViewModel.state.collectAsState()
    val financeState by orderFinanceViewModel.state.collectAsState()
    val actorRole = Role.entries.firstOrNull { it.name == roleLabel } ?: Role.Viewer
    val canManageOrders = roleLabel != "Viewer"

    LaunchedEffect(Unit) {
        viewModel.loadPage(limit = 5000)
        onActivity()
    }

    val atmosphere = Brush.verticalGradient(
        colors = listOf(
            Color(0xFFD6F0EB),
            Color(0xFFF4F3E8),
            Color(0xFFFFFDF8),
        ),
    )

    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(atmosphere)
            .padding(16.dp),
    ) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            verticalAlignment = Alignment.CenterVertically,
        ) {
            Column(modifier = Modifier.fillMaxWidth(0.7f)) {
                Text("Resources", style = MaterialTheme.typography.headlineMedium)
                Text(
                    text = "Role: $roleLabel",
                    style = MaterialTheme.typography.bodyMedium,
                    color = MaterialTheme.colorScheme.onBackground.copy(alpha = 0.75f),
                )
            }
            TextButton(onClick = onLogout) {
                Text("Logout")
            }
        }

        Spacer(Modifier.height(12.dp))

        Surface(
            modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(18.dp)),
            color = MaterialTheme.colorScheme.surface.copy(alpha = 0.9f),
            tonalElevation = 3.dp,
            shadowElevation = 4.dp,
        ) {
            Row(
                modifier = Modifier.fillMaxWidth().padding(horizontal = 14.dp, vertical = 12.dp),
                verticalAlignment = Alignment.CenterVertically,
            ) {
                Text(
                    text = "${state.resources.size} resources loaded",
                    style = MaterialTheme.typography.titleLarge,
                    color = MaterialTheme.colorScheme.primary,
                )
            }
        }

        Spacer(Modifier.height(12.dp))

        Surface(
            modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(18.dp)),
            color = MaterialTheme.colorScheme.surface.copy(alpha = 0.92f),
            tonalElevation = 3.dp,
            shadowElevation = 3.dp,
        ) {
            Column(modifier = Modifier.fillMaxWidth().padding(12.dp)) {
                Text("Order Workflow", style = MaterialTheme.typography.titleLarge)
                Spacer(Modifier.height(8.dp))
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Button(onClick = {
                        orderWorkflowViewModel.createPendingTenderDemo(actorRole, actorId)
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Create Pending")
                    }
                    Button(onClick = {
                        orderWorkflowViewModel.confirmLastOrder(actorRole)
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Confirm")
                    }
                }
                Spacer(Modifier.height(8.dp))
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Button(onClick = {
                        orderWorkflowViewModel.requestReturn(actorRole)
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Return")
                    }
                    Button(onClick = {
                        orderWorkflowViewModel.requestExchange(actorRole)
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Exchange")
                    }
                    Button(onClick = {
                        orderWorkflowViewModel.requestRefund(actorRole)
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Refund")
                    }
                }
                Spacer(Modifier.height(8.dp))
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Button(onClick = {
                        orderWorkflowViewModel.markAwaitingDelivery(actorRole)
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Ship")
                    }
                    Button(onClick = {
                        orderWorkflowViewModel.confirmDelivery(actorRole, "signed-${actorId}")
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Deliver")
                    }
                }
                Spacer(Modifier.height(8.dp))
                Button(onClick = {
                    orderWorkflowViewModel.suggestSlots(actorRole)
                    onActivity()
                }, enabled = canManageOrders) {
                    Text("Suggest 3 Slots")
                }
                if (!canManageOrders) {
                    Text(
                        text = "Order actions are restricted for Viewer role.",
                        style = MaterialTheme.typography.bodyMedium,
                        color = MaterialTheme.colorScheme.error,
                    )
                }
                if (orderState.lastOrderId != null) {
                    Text(
                        text = "Last: ${orderState.lastOrderId} (${orderState.lastOrderState.orEmpty()})",
                        style = MaterialTheme.typography.bodyMedium,
                    )
                }
                orderState.suggestedSlots.forEach { slot ->
                    Text("- $slot", style = MaterialTheme.typography.bodyMedium)
                }
            }
        }

        Spacer(Modifier.height(12.dp))

        Surface(
            modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(18.dp)),
            color = MaterialTheme.colorScheme.surface.copy(alpha = 0.92f),
            tonalElevation = 3.dp,
            shadowElevation = 3.dp,
        ) {
            Column(modifier = Modifier.fillMaxWidth().padding(12.dp)) {
                Text("Meeting Lifecycle", style = MaterialTheme.typography.titleLarge)
                Spacer(Modifier.height(8.dp))
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Button(onClick = {
                        meetingWorkflowViewModel.submitMeeting()
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Submit")
                    }
                    Button(onClick = {
                        meetingWorkflowViewModel.approve(actorRole)
                        onActivity()
                    }, enabled = roleLabel == "Supervisor" || roleLabel == "Admin") {
                        Text("Approve")
                    }
                    Button(onClick = {
                        meetingWorkflowViewModel.checkIn(actorRole)
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Check-in")
                    }
                }
                Spacer(Modifier.height(6.dp))
                Button(onClick = {
                    meetingWorkflowViewModel.markNoShowIfDue(actorRole)
                    onActivity()
                }, enabled = roleLabel == "Supervisor" || roleLabel == "Admin") {
                    Text("Mark No-show")
                }
                Text(
                    text = "Status: ${meetingState.status} ${meetingState.note?.let { "- $it" } ?: ""}",
                    style = MaterialTheme.typography.bodyMedium,
                )
            }
        }

        Spacer(Modifier.height(12.dp))

        Surface(
            modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(18.dp)),
            color = MaterialTheme.colorScheme.surface.copy(alpha = 0.92f),
            tonalElevation = 3.dp,
            shadowElevation = 3.dp,
        ) {
            Column(modifier = Modifier.fillMaxWidth().padding(12.dp)) {
                Text("Order & Invoice", style = MaterialTheme.typography.titleLarge)
                Spacer(Modifier.height(8.dp))
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Button(onClick = {
                        orderFinanceViewModel.addDemoItem(actorRole, actorId)
                        onActivity()
                    }, enabled = canManageOrders) { Text("Add Item") }
                    Button(onClick = {
                        orderFinanceViewModel.mergeFirstTwoItems(actorRole)
                        onActivity()
                    }, enabled = canManageOrders) { Text("Merge") }
                    Button(onClick = {
                        orderFinanceViewModel.splitFirstItem(actorRole)
                        onActivity()
                    }, enabled = canManageOrders) { Text("Split") }
                }
                Spacer(Modifier.height(8.dp))
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Button(onClick = {
                        orderFinanceViewModel.generateInvoice(
                            role = actorRole,
                            actorId = actorId,
                        )
                        onActivity()
                    }, enabled = canManageOrders) { Text("Invoice") }
                    Button(onClick = {
                        orderFinanceViewModel.refundLatest(
                            role = actorRole,
                            actorId = actorId,
                        )
                        onActivity()
                    }, enabled = canManageOrders) { Text("Refund") }
                }
                Text("Cart: ${financeState.cart.size} | Invoices: ${financeState.invoices.size} | Refunds: ${financeState.refunds.size}")
                if (financeState.note != null) {
                    Text(financeState.note.orEmpty(), style = MaterialTheme.typography.bodyMedium)
                }
            }
        }

        Spacer(Modifier.height(12.dp))

        if (state.isLoading) {
            Row(modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                CircularProgressIndicator(strokeWidth = 2.dp)
                Text(
                    text = "  Loading catalog...",
                    style = MaterialTheme.typography.bodyLarge,
                )
            }
        }

        Spacer(Modifier.height(8.dp))

        LazyColumn(modifier = Modifier.fillMaxSize()) {
            items(
                items = state.resources,
                key = { it.id },
                contentType = { "resource_row" },
            ) { resource ->
                Card(
                    shape = RoundedCornerShape(16.dp),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.93f),
                    ),
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 5.dp),
                ) {
                    Row(modifier = Modifier.fillMaxWidth().padding(12.dp), verticalAlignment = Alignment.CenterVertically) {
                        Column(modifier = Modifier.fillMaxWidth(0.72f)) {
                            Text(
                                text = resource.name,
                                style = MaterialTheme.typography.titleLarge,
                                fontWeight = FontWeight.SemiBold,
                            )
                            Text(
                                text = "Category: ${resource.category}",
                                style = MaterialTheme.typography.bodyMedium,
                                color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.7f),
                            )
                            if (resource.allergens.isNotBlank()) {
                                Text(
                                    text = "Allergens: ${resource.allergens}",
                                    style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.error.copy(alpha = 0.8f),
                                )
                            }
                        }
                        Text(
                            text = if (roleLabel == "Viewer") "Read-only" else "${resource.availableUnits} units",
                            style = MaterialTheme.typography.bodyLarge,
                            color = MaterialTheme.colorScheme.tertiary,
                        )
                    }
                }
            }
        }
    }
}
"}

