26	
27	data class OrderWorkflowState(
28	    val lastOrderId: String? = null,
29	    val lastOrderState: String? = null,
30	    val suggestedSlots: List<String> = emptyList(),
31	)
32	
33	class OrderWorkflowViewModel(
34	    private val orderDao: OrderDao,
35	    private val resourceDao: ResourceDao,
36	    private val stateMachine: OrderStateMachine,
37	    private val bookingUseCase: BookingUseCase,
38	    private val permissionEvaluator: PermissionEvaluator,
39	    private val validationService: ValidationService,
40	    private val clock: Clock,
41	) {
42	    private val scope = CoroutineScope(SupervisorJob() + Dispatchers.Default)
43	    private val _state = MutableStateFlow(OrderWorkflowState())
44	    val state: StateFlow<OrderWorkflowState> = _state.asStateFlow()
45	
46	    fun createPendingTenderDemo(role: Role, actorId: String) {
47	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
48	            _state.value = _state.value.copy(lastOrderState = "Denied")
49	            return
50	        }
51	        scope.launch(Dispatchers.IO) {
52	            ensureDemoResource()
53	            val orderId = "ord-${clock.now().toEpochMilliseconds()}"
54	            val now = clock.now().toEpochMilliseconds()
55	            val totalPrice = 25.50
56	            val priceError = validationService.validatePrice(totalPrice)
57	            if (priceError != null) {
58	                _state.value = _state.value.copy(lastOrderState = priceError)
59	                return@launch
60	            }
61	            val order = OrderEntity(
62	                id = orderId,
63	                userId = actorId,
64	                resourceId = "res-1",
65	                state = OrderState.Draft.name,
66	                startTime = now,
67	                endTime = clock.now().plus(30.minutes).toEpochMilliseconds(),
68	                expiresAt = null,
69	                quantity = 1,
70	                totalPrice = totalPrice,
71	            )
72	            orderDao.upsert(order)
73	            val transitionError = stateMachine.transitionToPendingTender(orderId)
74	            if (transitionError != null) {
75	                _state.value = _state.value.copy(lastOrderState = transitionError)
76	                return@launch
77	            }
78	            _state.value = _state.value.copy(lastOrderId = orderId, lastOrderState = OrderState.PendingTender.name)
79	        }
80	    }
81	
82	    fun confirmLastOrder(role: Role) {
83	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
84	            _state.value = _state.value.copy(lastOrderState = "Denied")
85	            return
86	        }
87	        scope.launch(Dispatchers.IO) {
88	            val orderId = _state.value.lastOrderId ?: return@launch
89	            stateMachine.confirm(orderId)
90	            _state.value = _state.value.copy(lastOrderState = OrderState.Confirmed.name)
91	        }
92	    }
93	
94	    fun requestReturn(role: Role) {
95	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
96	            _state.value = _state.value.copy(lastOrderState = "Denied")
97	            return
98	        }
99	        scope.launch(Dispatchers.IO) {
100	            val orderId = _state.value.lastOrderId ?: return@launch
101	            val success = stateMachine.requestReturn(orderId)
102	            _state.value = _state.value.copy(
103	                lastOrderState = if (success) OrderState.ReturnRequested.name else "Return not allowed",
104	            )
105	        }
106	    }
107	
108	    fun completeReturn(role: Role) {
109	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Approve)) {
110	            _state.value = _state.value.copy(lastOrderState = "Denied")
111	            return
112	        }
113	        scope.launch(Dispatchers.IO) {
114	            val orderId = _state.value.lastOrderId ?: return@launch
115	            val success = stateMachine.completeReturn(orderId)
116	            _state.value = _state.value.copy(
117	                lastOrderState = if (success) OrderState.Returned.name else "Complete return not allowed",
118	            )
119	        }
120	    }
121	
122	    fun requestExchange(role: Role) {
123	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
124	            _state.value = _state.value.copy(lastOrderState = "Denied")
125	            return
126	        }
127	        scope.launch(Dispatchers.IO) {
128	            val orderId = _state.value.lastOrderId ?: return@launch
129	            val success = stateMachine.requestExchange(orderId)
130	            _state.value = _state.value.copy(
131	                lastOrderState = if (success) OrderState.ExchangeRequested.name else "Exchange not allowed",
132	            )
133	        }
134	    }
135	
136	    fun requestRefund(role: Role) {
137	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
138	            _state.value = _state.value.copy(lastOrderState = "Denied")
139	            return
140	        }
141	        scope.launch(Dispatchers.IO) {
142	            val orderId = _state.value.lastOrderId ?: return@launch
143	            val success = stateMachine.requestRefund(orderId)
144	            _state.value = _state.value.copy(
145	                lastOrderState = if (success) OrderState.RefundRequested.name else "Refund not allowed",
146	            )
147	        }
148	    }
149	
150	    fun completeRefund(role: Role) {
151	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Approve)) {
152	            _state.value = _state.value.copy(lastOrderState = "Denied")
153	            return
154	        }
155	        scope.launch(Dispatchers.IO) {
156	            val orderId = _state.value.lastOrderId ?: return@launch
157	            val success = stateMachine.completeRefund(orderId)
158	            _state.value = _state.value.copy(
159	                lastOrderState = if (success) OrderState.Refunded.name else "Complete refund not allowed",
160	            )
161	        }
162	    }
163	
164	    fun markAwaitingDelivery(role: Role) {
165	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
166	            _state.value = _state.value.copy(lastOrderState = "Denied")
167	            return
168	        }
169	        scope.launch(Dispatchers.IO) {
170	            val orderId = _state.value.lastOrderId ?: return@launch
171	            val success = stateMachine.markAwaitingDelivery(orderId)
172	            _state.value = _state.value.copy(
173	                lastOrderState = if (success) OrderState.AwaitingDelivery.name else "Cannot start delivery",
174	            )
175	        }
176	    }
177	
178	    fun confirmDelivery(role: Role, signature: String) {
179	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
180	            _state.value = _state.value.copy(lastOrderState = "Denied")
181	            return
182	        }
183	        scope.launch(Dispatchers.IO) {
184	            val orderId = _state.value.lastOrderId ?: return@launch
185	            val success = stateMachine.confirmDelivery(orderId, signature)
186	            _state.value = _state.value.copy(
187	                lastOrderState = if (success) OrderState.Delivered.name else "Cannot confirm delivery",
188	            )
189	        }
190	    }
191	
192	    fun suggestSlots(role: Role) {
193	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Read)) {
194	            _state.value = _state.value.copy(suggestedSlots = emptyList())
195	            return
196	        }
197	        scope.launch(Dispatchers.IO) {
198	            ensureDemoResource()
199	            val slots = bookingUseCase.findThreeAvailableSlots(
200	                resourceId = "res-1",
201	                duration = 30.minutes,
202	            )
203	            val zone = TimeZone.currentSystemDefault()
204	            _state.value = _state.value.copy(
205	                suggestedSlots = slots.map {
206	                    val start = it.start.toLocalDateTime(zone)
207	                    "${start.date} ${start.time.hour.toString().padStart(2, '0')}:${start.time.minute.toString().padStart(2, '0')}"
208	                },
209	            )
210	        }
211	    }
212	
213	    private suspend fun ensureDemoResource() {
214	        if (resourceDao.getById("res-1") != null) return
215	        resourceDao.upsert(
216	            ResourceEntity(
217	                id = "res-1",
218	                name = "Premium Hall",
219	                category = "Operations",
220	                availableUnits = 4,
221	                unitPrice = 25.50,
222	                allergens = "none",
223	            ),
224	        )
225	    }
226	
227	    fun clearSessionState() {
228	        _state.value = OrderWorkflowState()
229	    }
230	}
