)

class LocalAuthService {
    private data class CredentialRecord(
        val username: String,
        val passwordHash: String,
        val displayName: String,
        val role: Role,
        val delegateFor: String? = null,
    )

    private val credentials: Map<String, CredentialRecord>

    init {
        val records = listOf(
            CredentialRecord("admin", computeHash("admin", "Admin1234!"), "Avery Admin", Role.Admin),
            CredentialRecord("supervisor", computeHash("supervisor", "Super1234!"), "Sky Supervisor", Role.Supervisor),
            CredentialRecord("operator", computeHash("operator", "Oper12345!"), "Olive Operator", Role.Operator),
            CredentialRecord("viewer", computeHash("viewer", "Viewer1234"), "Vera Viewer", Role.Viewer),
            CredentialRecord("companion", computeHash("companion", "Companion1!"), "Casey Companion", Role.Companion, delegateFor = "operator"),
        )
        credentials = records.associateBy { it.username }
    }

    fun authenticate(username: String, password: String): AuthPrincipal? {
        val record = credentials[username] ?: return null
        val candidateHash = computeHash(username, password)
        if (record.passwordHash != candidateHash) return null
        return AuthPrincipal(
            userId = record.username,
            displayName = record.displayName,
            role = record.role,
            delegateForUserId = record.delegateFor,
        )
    }

    companion object {
        private fun computeHash(username: String, password: String): String {
            return pbkdf2Hash(password = password, salt = "$username|task136")
        }
    }
