import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertNotNull
import kotlin.test.assertNull
import kotlin.test.assertTrue

class OrderStateMachineTest {

    @Test
    fun `validatePrice rejects price below minimum`() {
        val sm = createTestStateMachine()
        val error = sm.validatePrice(0.001)
        assertNotNull(error)
        assertTrue(error.contains("at least"))
    }

    @Test
    fun `validatePrice rejects price above maximum`() {
        val sm = createTestStateMachine()
        val error = sm.validatePrice(10_000.00)
        assertNotNull(error)
        assertTrue(error.contains("exceed"))
    }

    @Test
    fun `validatePrice accepts valid price`() {
        val sm = createTestStateMachine()
        val error = sm.validatePrice(25.50)
        assertNull(error)
    }

    @Test
    fun `validatePrice accepts boundary minimum`() {
        val sm = createTestStateMachine()
        assertNull(sm.validatePrice(0.01))
    }

    @Test
    fun `validatePrice accepts boundary maximum`() {
        val sm = createTestStateMachine()
        assertNull(sm.validatePrice(9_999.99))
    }

    @Test
    fun `OrderState enum has all expected states`() {
        val expected = setOf(
            "Draft", "PendingTender", "Confirmed", "Cancelled", "Expired",
            "PartiallyFulfilled", "ReturnRequested", "Returned",
            "ExchangeRequested", "Exchanged", "RefundRequested", "Refunded",
            "AwaitingDelivery", "Delivered",
        )
        val actual = OrderState.entries.map { it.name }.toSet()
        assertEquals(expected, actual)
    }

    @Test
    fun `DeliveryState enum has all expected states`() {
        val expected = setOf("None", "AwaitingDelivery", "InTransit", "Delivered", "DeliveryConfirmed")
        val actual = DeliveryState.entries.map { it.name }.toSet()
        assertEquals(expected, actual)
    }

    @Test
    fun `PaymentMethod enum has all expected values`() {
        val expected = setOf("Cash", "InternalWallet", "ExternalTender")
        val actual = PaymentMethod.entries.map { it.name }.toSet()
        assertEquals(expected, actual)
    }

    @Test
    fun `state transitions follow valid paths from Draft`() {
        // Draft can only go to PendingTender
        val draft = OrderState.Draft
        val pendingTender = OrderState.PendingTender
        // This tests the enum values exist and are distinct
        assertTrue(draft != pendingTender)
    }

    @Test
    fun `return states exist for post-purchase flow`() {
        assertNotNull(OrderState.valueOf("ReturnRequested"))
        assertNotNull(OrderState.valueOf("Returned"))
        assertNotNull(OrderState.valueOf("ExchangeRequested"))
        assertNotNull(OrderState.valueOf("Exchanged"))
        assertNotNull(OrderState.valueOf("RefundRequested"))
        assertNotNull(OrderState.valueOf("Refunded"))
    }

    @Test
    fun `delivery states exist for fulfillment flow`() {
        assertNotNull(OrderState.valueOf("AwaitingDelivery"))
        assertNotNull(OrderState.valueOf("Delivered"))
        assertNotNull(DeliveryState.valueOf("DeliveryConfirmed"))
    }

    /**
     * Creates a minimal OrderStateMachine for price validation tests.
     * DB-dependent methods (transitions) require integration tests with a real Room DB.
     */
    @Suppress("UNCHECKED_CAST")
    private fun createTestStateMachine(): OrderStateMachine {
        // OrderStateMachine.validatePrice() is a pure function that doesn't touch the DB,
        // so we can construct with null DB for these tests.
        return OrderStateMachine(
            database = null as com.eaglepoint.task136.shared.db.AppDatabase,
            clock = kotlinx.datetime.Clock.System,
        )
    }
}
"}

