import kotlin.test.Test
import kotlin.test.assertFalse
import kotlin.test.assertTrue

class AuthViewModelTest {
    private val fakeUserDao = object : UserDao {
        private val users = mutableMapOf<String, UserEntity>()

        override suspend fun upsert(user: UserEntity) { users[user.id] = user }
        override suspend fun getById(id: String) = users[id]
        override suspend fun countAll() = users.size
        override suspend fun update(user: UserEntity) { users[user.id] = user }
        override suspend fun getAllActive() = users.values.filter { it.isActive }
    }

    @Test
    fun `valid credentials authenticate`() {
        runBlocking {
            val authService = LocalAuthService(fakeUserDao)
            authService.seedDemoAccountsIfNeeded()

            val viewModel = AuthViewModel(
                securityRepository = SecurityRepository(clock = testClock, userDao = fakeUserDao),
                authService = authService,
                clock = testClock,
            )

            viewModel.updateUsername("admin")
            viewModel.updatePassword("Admin1234!")
            viewModel.login()

            // login is async, give it a moment
            Thread.sleep(300)
            assertTrue(viewModel.state.value.isAuthenticated)
        }
    }

    @Test
    fun `invalid credentials stay unauthenticated`() {
        runBlocking {
            val authService = LocalAuthService(fakeUserDao)
            authService.seedDemoAccountsIfNeeded()

            val viewModel = AuthViewModel(
                securityRepository = SecurityRepository(clock = testClock, userDao = fakeUserDao),
                authService = authService,
                clock = testClock,
            )

            viewModel.updateUsername("admin")
            viewModel.updatePassword("wrong11111")
            viewModel.login()

            Thread.sleep(300)
            assertFalse(viewModel.state.value.isAuthenticated)
        }
    }
}

private val testClock = object : Clock {
    override fun now(): Instant = Instant.parse("2026-03-30T10:00:00Z")
}
"}

