import com.eaglepoint.task136.shared.rbac.Role
import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertFalse
import kotlin.test.assertTrue

class AppNavigationTest {

    @Test
    fun `viewer cannot access order detail`() {
        assertFalse(AppNavigator.isScreenAllowed(Screen.OrderDetail("ord-1"), Role.Viewer))
    }

    @Test
    fun `viewer cannot access cart`() {
        assertFalse(AppNavigator.isScreenAllowed(Screen.Cart, Role.Viewer))
    }

    @Test
    fun `viewer can access dashboard`() {
        assertTrue(AppNavigator.isScreenAllowed(Screen.Dashboard, Role.Viewer))
    }

    @Test
    fun `viewer can access calendar`() {
        assertTrue(AppNavigator.isScreenAllowed(Screen.Calendar, Role.Viewer))
    }

    @Test
    fun `admin can access all screens`() {
        assertTrue(AppNavigator.isScreenAllowed(Screen.Dashboard, Role.Admin))
        assertTrue(AppNavigator.isScreenAllowed(Screen.Calendar, Role.Admin))
        assertTrue(AppNavigator.isScreenAllowed(Screen.OrderDetail("x"), Role.Admin))
        assertTrue(AppNavigator.isScreenAllowed(Screen.Cart, Role.Admin))
        assertTrue(AppNavigator.isScreenAllowed(Screen.InvoiceDetail("x"), Role.Admin))
        assertTrue(AppNavigator.isScreenAllowed(Screen.MeetingDetail("x"), Role.Admin))
    }

    @Test
    fun `companion can access orders and meetings but no invoices`() {
        assertTrue(AppNavigator.isScreenAllowed(Screen.OrderDetail("x"), Role.Companion))
        assertTrue(AppNavigator.isScreenAllowed(Screen.MeetingDetail("x"), Role.Companion))
        assertFalse(AppNavigator.isScreenAllowed(Screen.InvoiceDetail("x"), Role.Companion))
    }

    @Test
    fun `navigator blocks unauthorized navigation`() {
        val nav = AppNavigator()
        val result = nav.navigateTo(Screen.OrderDetail("ord-1"), Role.Viewer)
        assertFalse(result)
        assertEquals(Screen.Dashboard, nav.currentScreen.value)
    }

    @Test
    fun `navigator allows authorized navigation`() {
        val nav = AppNavigator()
        val result = nav.navigateTo(Screen.OrderDetail("ord-1"), Role.Admin)
        assertTrue(result)
        assertEquals(Screen.OrderDetail("ord-1"), nav.currentScreen.value)
    }

    @Test
    fun `back navigation works`() {
        val nav = AppNavigator()
        nav.navigateTo(Screen.Calendar)
        nav.navigateTo(Screen.Cart)
        nav.goBack()
        assertEquals(Screen.Calendar, nav.currentScreen.value)
        nav.goBack()
        assertEquals(Screen.Dashboard, nav.currentScreen.value)
    }

    @Test
    fun `reset clears back stack`() {
        val nav = AppNavigator()
        nav.navigateTo(Screen.Calendar)
        nav.navigateTo(Screen.Cart)
        nav.resetToDashboard()
        assertEquals(Screen.Dashboard, nav.currentScreen.value)
        assertFalse(nav.goBack())
    }
}
"}

