        assertEquals("Returned", orders.get("o1")?.state)
        assertEquals(5, resources.get("r1")?.availableUnits) // 2 + 3 restocked
    }

    @Test
    fun `confirm transitions from PendingTender`() {
        val orders = FakeOrderStore()
        orders.put(makeOrder("o1", "PendingTender"))
        val sm = createSM(orders)

        runBlockingTest { sm.confirm("o1") }
        assertEquals("Confirmed", orders.get("o1")?.state)
        assertNull(orders.get("o1")?.expiresAt)
    }

    @Test
    fun `refund request allowed from Confirmed`() {
        val orders = FakeOrderStore()
        orders.put(makeOrder("o1", "Confirmed"))
        val sm = createSM(orders)

        assertTrue(runBlockingTest { sm.requestRefund("o1") })
        assertEquals("RefundRequested", orders.get("o1")?.state)
    }

    @Test
    fun `refund request rejected from Draft`() {
        val orders = FakeOrderStore()
        orders.put(makeOrder("o1", "Draft"))
        val sm = createSM(orders)

        assertFalse(runBlockingTest { sm.requestRefund("o1") })
    }

    @Test
    fun `complete refund restocks inventory`() {
        val orders = FakeOrderStore()
        val resources = FakeResourceStore()
        orders.put(makeOrder("o1", "RefundRequested", quantity = 2, resourceId = "r1"))
        resources.put(ResourceEntity("r1", "Hall", "Ops", availableUnits = 5, unitPrice = 10.0))
        val sm = createSM(orders, resources)

        assertTrue(runBlockingTest { sm.completeRefund("o1") })
        assertEquals("Refunded", orders.get("o1")?.state)
        assertEquals(7, resources.get("r1")?.availableUnits) // 5 + 2
    }

    @Test
    fun `exchange request allowed from Confirmed`() {
        val orders = FakeOrderStore()
        orders.put(makeOrder("o1", "Confirmed"))
        val sm = createSM(orders)

        assertTrue(runBlockingTest { sm.requestExchange("o1") })
        assertEquals("ExchangeRequested", orders.get("o1")?.state)
    }

    @Test
    fun `delivery flow Confirmed to AwaitingDelivery to Delivered`() {
        val orders = FakeOrderStore()
        orders.put(makeOrder("o1", "Confirmed"))
        val sm = createSM(orders)

        assertTrue(runBlockingTest { sm.markAwaitingDelivery("o1") })
