    }

    @Test
    fun `delivery rejected from non-Confirmed state`() {
        val orders = FakeOrderStore()
        orders.put(makeOrder("o1", "Draft"))
        val sm = createSM(orders)

        assertFalse(runBlockingTest { sm.markAwaitingDelivery("o1") })
    }

    @Test
    fun `expire stale orders marks expired and restocks`() {
        val orders = FakeOrderStore()
        val resources = FakeResourceStore()
        orders.put(makeOrder("o1", "PendingTender", expiresAt = 100L, quantity = 2, resourceId = "r1"))
        resources.put(ResourceEntity("r1", "Hall", "Ops", availableUnits = 3, unitPrice = 10.0))
        val sm = createSM(orders, resources, clockMillis = 200L)

        runBlockingTest { sm.expireStaleOrders() }
        assertEquals("Expired", orders.get("o1")?.state)
        assertEquals(5, resources.get("r1")?.availableUnits) // 3 + 2
    }

