    }

    @Test
    fun `non-null order ID required for all operations`() {
        val orders = FakeOrderStore()
        val sm = createSM(orders)

        assertFalse(runBlockingTest { sm.requestReturn("nonexistent") })
        assertFalse(runBlockingTest { sm.requestRefund("nonexistent") })
        assertFalse(runBlockingTest { sm.markAwaitingDelivery("nonexistent") })
