    private fun makeOrder(
        id: String,
        state: String,
        quantity: Int = 1,
        resourceId: String = "r1",
        expiresAt: Long? = null,
    ) = OrderEntity(
        id = id, userId = "u1", resourceId = resourceId, state = state,
        startTime = 0L, endTime = 100L, expiresAt = expiresAt,
        quantity = quantity, totalPrice = quantity * 10.0,
    )

