        return createSM(FakeOrderStore())
    }

    private fun createSM(
        orders: FakeOrderStore = FakeOrderStore(),
        resources: FakeResourceStore = FakeResourceStore(),
        clockMillis: Long = 0L,
    ): OrderStateMachine {
        val db = FakeAppDatabase(orders, resources)
        val clock = object : kotlinx.datetime.Clock {
            override fun now() = kotlinx.datetime.Instant.fromEpochMilliseconds(clockMillis)
        }
        return OrderStateMachine(db, clock)
    }
