                            roleLabel = role,
                            actorId = actor,
                            onBack = { navigator.goBack() },
                            onActivity = authViewModel::touchSession,
                        )
                    }
                }
                is Screen.MeetingDetail -> {
                    if (!AppNavigator.isScreenAllowed(screen, roleEnum)) {
                        navigator.resetToDashboard()
                    } else {
                        MeetingDetailScreen(
                            meetingId = screen.meetingId,
